const REAWAKEN_DATA=[
{name:"ASI/Feat",cost:300,tier:0,category:"อื่นๆ",source:"-",description:"สามารถเลือกเพิ่ม Ability Score หรือ Feat ได้เมื่อซื้อแต่ละครั้ง",notes:"สูงสุด 3 อันต่อตัวละคร"},
{name:"Artifact 2nd Slot",cost:600,tier:0,category:"อื่นๆ",source:"-",description:"เพิ่มจำนวน Artifact ที่ตัวละครสามารถครอบครองได้เป็น 2 อัน",notes:""},
{name:"Boon Slot",cost:300,tier:0,category:"อื่นๆ",source:"-",description:"เพิ่มจำนวน Boon ที่ตัวละครสามารถครอบครองได้เป็น 4 อัน",notes:""},
{name:"เพิ่ม Stat สูงสุด",cost:500,tier:0,category:"อื่นๆ",source:"-",description:"เพิ่ม Stat และค่าสูงสุดขึ้น 2 หน่วย",notes:"เลือกได้ 1 ครั้งต่อ Stat ต่อตัวละคร"},
{name:"Blessing of Protection",cost:200,tier:1,category:"Blessing",source:"DMG, p228",description:"You gain a +1 bonus to AC and saving throws",notes:""},
{name:"Blessing of the Morninglord",cost:100,tier:2,category:"Blessing",source:"IDRotF, p119",description:"You gain 10 temporary hit points each day at dawn.",notes:""},
{name:"Blessing of the Solipsistic Mind",cost:100,tier:2,category:"Blessing",source:"PaBTSO",description:"You access esoteric truths from an ancient tome by focusing deeply on your own thoughts. You can take an action to focus your inner mind. This focus lasts for 1 hour. While your inner mind is focused, you can't take reactions. For the duration, when you make an Intelligence check, Wisdom check, Intelligence saving throw, or Wisdom saving throw, you can roll a d8 and add the number rolled to the ability check or saving throw. You regain the ability to focus your inner mind when you finish a long rest.",notes:""},
{name:"Blessing of Weapon Enhancement",cost:100,tier:2,category:"Blessing",source:"DMG/228",description:"One nonmagical weapon in your possession becomes a +1 weapon whenever you wield it.",notes:""},
{name:"The Blessed of Corellon",cost:100,tier:2,category:"Blessing",source:"MTF, p45",description:"The rarest of these blessed elves can change their sex whenever they finish a long rest-a miracle celebrated by elves of all sorts except drow. Dark elves find this ability to be terrifying and characterize it as a curse, for it could destabilize their entire society. If Corellon's blessing manifests in a drow, that elf usually flees to the surface world to seek shelter among those dedicated to Corellon.",notes:"นับว่าเป็น Blessing และนำข้อจำกัดเรื่องเผ่าออก"},
{name:"Blessing of Wound Closure",cost:100,tier:2,category:"Blessing",source:"DMG, p228",description:"This blessing grants you the benefits of a periapt of wound closure.",notes:""},
{name:"Blessing of Dumathoin",cost:200,tier:3,category:"Blessing",source:"PaBTSO",description:"Your eyes become keen enough to pick out hidden secrets. You gain darkvision. If you already had darkvision, you can see in color in the dark. In addition, you can use an action to gain truesight for 1 minute. Once you gain truesight in this way, you can't do so again until you finish a long rest.",notes:""},
{name:"Blessing of Bloody Might",cost:600,tier:4,category:"Blessing",source:"BMT p171",description:"Your Strength score increases by 2, to a maximum of 22.",notes:""},
{name:"Blessing of Health",cost:600,tier:4,category:"Blessing",source:"DMG, p228",description:"Your Constitution score increases by 2, up to a maximum of 22.",notes:""},
{name:"Blessing of Lonely Genius",cost:600,tier:4,category:"Blessing",source:"BMT p171",description:"Your Intelligence score increases by 2, to a maximum of 22.",notes:""},
{name:"Blessing of Understanding",cost:600,tier:4,category:"Blessing",source:"DMG, p228",description:"Your Wisdom score increases by 2, up to a maximum of 22.",notes:""},
{name:"Blessing of the Frostmaiden",cost:400,tier:4,category:"Blessing",source:"IDRotF, p213",description:"Your eyes become as cold as ice. You gain immunity to cold damage. In addition, you can cast the cone of cold spell (save DC = PB+Con+8) once. You regain the ability to cast this spell when you finish a long rest.",notes:""},
{name:"Blessing of Magic Resistance",cost:700,tier:4,category:"Blessing",source:"DMG, p228",description:"You have advantage on saving throws against spells and other magical effects.",notes:""},
{name:"Azorius Charm",cost:100,tier:1,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the hold person (3rd-level version), command, or counterspell spell. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Boros Charm",cost:100,tier:1,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the crusader's mantle or haste spell. Alternatively, you can cast the guiding bolt spell, and if it hits, you regain a number of hit points equal to the damage it deals. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Agelessness",cost:100,tier:1,category:"Charm",source:"BGDIA p215",description:"While you have this charm, you don't age naturally, and your skin gains the waxy complexion of a doll. Magical aging still affects you, however. This charm vanishes from you when you die.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Air Bubbles",cost:100,tier:1,category:"Charm",source:"BAM p17",description:"This charm allows you to cast the Air Bubble spell (see the Astral Adventurer's Guide) as an action. Once used three times, this charm goes away.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Animal Conjuring",cost:100,tier:1,category:"Charm",source:"DMG, p228",description:"This charm allows you to cast the conjure animals spell (3rd-level version) as an action. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Bounty",cost:100,tier:1,category:"Charm",source:"IDRotF, p283",description:"This charm has 3 charges. As an action, you can expend 1 of the charm's charges to cast the create food and water spell, requiring no components. Once all its charges have been expended, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Cold Resistance",cost:100,tier:1,category:"Charm",source:"IDRotF, p283",description:"This charm allows you to give yourself resistance to cold damage as an action. This benefit lasts for 24 hours, after which the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Darkvision",cost:100,tier:1,category:"Charm",source:"DMG, p228",description:"This charm allows you to cast the darkvision spell as an action, no components required. Once used three times, the charm goes away.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Eldritch Eye",cost:100,tier:1,category:"Charm",source:"VNotEE",description:"You can cast Clairvoyance as an action, without using a spell slot and requiring no material components. Once used three times, the charm vanishes.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Feather Falling",cost:100,tier:1,category:"Charm",source:"DMG, p228",description:"This charm grants you the benefits of a ring of feather falling. These benefits last for 10 days, after which the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Heroism",cost:100,tier:1,category:"Charm",source:"DMG, p228",description:"This charm allows you to give yourself the benefit of a potion of heroism as an action. Once you do so, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Instant Tools",cost:100,tier:1,category:"Charm",source:"BAM p17",description:"This charm allows you to magically conjure a set of artisan's tools, navigator's tools, or thieves' tools. The conjured tools appear either in your hand or somewhere else in your space (your choice). Once used, this charm goes away, but the tools remain.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Ruin",cost:100,tier:1,category:"Charm",source:"BMT p62",description:"As an action, you can touch a nonmagical object, or a section of a larger nonmagical object, that fits in a 5-foot cube. The target is reduced to dust. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Key",cost:100,tier:1,category:"Charm",source:"BMT p62",description:"As a bonus action, you can touch a nonmagical melee weapon and imbue it with magic for 1 hour. For the duration, the weapon deals an extra 1d8 force damage on a hit and deals double damage to objects and structures. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Jester",cost:100,tier:1,category:"Charm",source:"BMT p62",description:"You can cast Tasha's Hideous Laughter, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Snowball Strike",cost:100,tier:1,category:"Charm",source:"IDRotF, p283",description:"This charm has 5 charges. As a bonus action, you can expend 1 of the charm's charges to create a magical snowball in your hand and throw it. You must have a hand free to hold the snowball, or the charge is wasted. The snowball is a magic ranged weapon with which you are proficient. It has a normal range of 20 feet and a long range of 60 feet, it deals 1d4 cold damage on a hit, and it scores a critical hit on a roll of 19 or 20. If you score a critical hit with the snowball, the target is blinded until the end of its next turn. The snowball vanishes immediately after you hit or miss with it, or at the end of your turn if you don't throw it. Once all its charges have been expended, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Crystal Heart",cost:100,tier:1,category:"Charm",source:"ToA, p167",description:"This charm grants you immunity to piercing and slashing damage from nonmagical attacks, but you gain vulnerability to bludgeoning damage. These effects last for 10 days, after which the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Ghoul",cost:100,tier:1,category:"Charm",source:"ToA, p167",description:"This charm allows you to use an action to eat a mouthful of flesh from a humanoid that has been dead no longer than 1 day. When you do, you regain 3d8 + 3 hit points. Once used three times, the charm goes away.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Ice Troll",cost:100,tier:1,category:"Charm",source:"IDRotF/283",description:"This charm allows you to use your reaction when you take cold damage to reduce the damage to 0. You regain a number of hit points equal to half the cold damage you would have taken. Once you do so, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Maimed",cost:100,tier:1,category:"Charm",source:"ToA, p167",description:"This charm allows you to regrow a lost appendage or organ, such as an arm, a foot, or an eye. After it is used once, the charm goes away.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Mirage",cost:100,tier:1,category:"Charm",source:"CM, p12",description:"This charm allows you to cast the hallucinatory terrain spell (save DC 15) as an action. Once used, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Slayer",cost:100,tier:1,category:"Charm",source:"DMG, p228",description:"One sword in your possession becomes a dragon slayer or giant slayer (DM's choice) for the next 9 days. The charm then vanishes from you and the weapon returns to normal.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Snow Walker",cost:100,tier:1,category:"Charm",source:"IDRotF, p283",description:"This charm has 3 charges. As an action, you can expend 1 of the charm's charges to gain the following benefits for 24 hours:\n\nYou and your allies within 15 feet of you ignore difficult terrain caused by snow or ice.\nYou can see through areas heavily obscured by snow to a distance of 60 feet.\nYou are immune to the effects of extreme cold, as described in the Dungeon Master's Guide (though you gain no protection from cold damage).\nOnce all its charges have been expended, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Storm",cost:100,tier:1,category:"Charm",source:"DIP, p41",description:"You become charged with the power of the storm, to the extent that tiny sparks crackle in your eyes. You can cast the lightning bolt spell (3rd-level version) as an action. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Swollen Hag",cost:100,tier:1,category:"Charm",source:"ToA, p167",description:"This charm allows you to spit up a frog as an action. The frog understands you and obeys your commands. Once used three times, the charm goes away.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Water Bearer",cost:100,tier:1,category:"Charm",source:"CM, p212",description:"This charm allows you to create up to 1 gallon of fresh water, which fills one or more empty containers in your possession. You can do this up to thrice per day for 10 days, after which this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Treasure Sense",cost:100,tier:1,category:"Charm",source:"ToA, p167",description:"While this charm lasts, you can use an action to pinpoint, by scent, the location of precious metals and stones, such as coins and gems, within 30 feet of you. The effect lasts for 3 days, after which the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Clay No-Face's Charm",cost:100,tier:1,category:"Charm",source:"ToA, p179",description:"While you have Clay No-Face in your possession, you don't need to eat, drink, or breathe. These benefits last for 30 days while the doll is in your possession, after which the charm vanishes from you.\n\nThe doll is a Tiny construct. Destroying the doll causes the child's soul within it to become trapped in the Soulmonger.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Golgari Charm",cost:100,tier:1,category:"Charm",source:"GGR, p174",description:"When you activate this charm, you can cast the dispel magic, false life (3rd-level version), or stinking cloud spell. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Izzet Charm",cost:100,tier:1,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the dispel magic or lightning bolt spell. Alternatively, as an action, you can regain one expended spell slot of 3rd level or lower. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Joho's Charm",cost:100,tier:1,category:"Charm",source:"ToA, p179",description:"While you have Joho in your possession, it grants you the benefit of a helm of comprehending languages. This benefit lasts for 7 days while the doll is in your possession, after which the charm vanishes from you.\n\nThe doll is a Tiny construct. Destroying the doll causes the child's soul within it to become trapped in the Soulmonger.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Rakdos Charm",cost:100,tier:1,category:"Charm",source:"GGR, p174",description:"When you activate this charm, you can cast the crown of madness, hellish rebuke, or shatter spell. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Simic Charm",cost:100,tier:1,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the enhance ability (3rd-level version), enlarge/reduce, or gaseous form spell. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Balance",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"When a creature you can see within 60 feet of you damages you, you can use your reaction to deal an amount of force damage to that creature equal to half the damage you took. Once used three times, the charm vanishes from you",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Biting Cold",cost:100,tier:2,category:"Charm",source:"IDRotF, p283",description:"This charm has 3 charges. As a bonus action, you can expend 1 of the charm's charges to wreathe your weapon attacks with biting cold for 1 minute. Until this effect ends, you deal an extra 1d6 cold damage when you hit with a melee or ranged weapon attack. Once all its charges have been expended, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Creeping Hand",cost:100,tier:2,category:"Charm",source:"VNotEE",description:"Once per turn, when you hit a creature with an attack roll using a weapon or an unarmed strike, you can infuse your strike with life-stealing energy. Your attack then deals an extra 1d10 necrotic damage, and you gain 5 temporary hit points. Once used five times, the charm vanishes.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Euryale",cost:200,tier:2,category:"Charm",source:"BMT p62",description:"As an action, you can unleash a petrifying wave of magic from your eyes in a 30-foot cone. Each creature in that area must make a DC 15 Constitution saving throw. On a failed save, a creature has the petrified condition for 1 hour. On a successful save, a creature is partially turned to stone and has the restrained condition. A restrained creature can repeat the save at the end of each of its turns, ending the effect on itself on a success.\n\nOnce you use this charm, it vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Many Tongues",cost:200,tier:2,category:"Charm",source:"BGDIA p215",description:"You can speak and understand all languages, you gain proficiency in the Deception and Persuasion skills, and you can add double your normal proficiency bonus when using those skills. This charm vanishes from you when you die.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Restoration",cost:100,tier:2,category:"Charm",source:"DMG, p228",description:"This charm has 6 charges. You can use an action to expend some of its charges to cast one of the following spells: greater restoration (4 charges) or lesser restoration (2 charges). Once all its charges have been expended, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Comet",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"As an action, you can force a creature you can see within 60 feet of you to focus on you. For 1 minute, creatures other than you and the target are invisible to the target. The effect ends if any creature other than you damages the target or forces the target to make a saving throw. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Donjon",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Otiluke's Resilient Sphere, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Fool",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Major Image, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). When you cast the spell in this way, it lasts its full duration with no concentration required. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Sage",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Divination, requiring no material components and using your Intelligence as the spellcasting ability. Once you cast the spell three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Skull",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"As a bonus action, you can transform into a deathly apparition. Your game statistics are replaced by those of a wraith, except for your alignment and personality; your Intelligence, Wisdom, and Charisma scores; and your passive Wisdom (Perception) score and languages. You don't have the wraith's Create Specter ability. Your equipment vanishes when you transform but returns when the transformation ends. The transformation lasts for 1 minute, until your wraith form is reduced to 0 hit points, or until you use a bonus action to end it. If the wraith form is reduced to 0 hit points and there is still damage left over, the remaining damage applies to your normal hit points. Once used three times, the charm vanishes from you",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Star",cost:200,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Enhance Ability, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). When you cast the spell in this way, it lasts its full duration with no concentration required. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Talons",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"As an action, you can cast Dispel Magic, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). If you successfully end any spells with it, you gain 1d6 temporary hit points for each spell level of the highest-level spell ended. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Rogue",cost:200,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Mislead, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). When you cast the spell in this way, it lasts its full duration with no concentration required. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Puzzle",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Hypnotic Pattern, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Vitality",cost:100,tier:2,category:"Charm",source:"DMG, p228",description:"This charm allows you to give yourself the benefit of a potion of vitality as an action. Once you do so, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Void",cost:100,tier:2,category:"Charm",source:"BMT p62",description:"You can cast Banishment, requiring no material components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Dimir Charm",cost:100,tier:2,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the blink or sleep (3rd-level version) spell. Alternatively, when you take damage, you can use your reaction to turn invisible and teleport up to 30 feet to an unoccupied space you can see. You remain invisible until the start of your next turn or until you attack or cast a spell. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Gruul Charm",cost:100,tier:2,category:"Charm",source:"GGR, p173",description:"When you activate this charm, you can cast the heroism or thunderwave spell (3rd-level versions). Alternatively, as a reaction when you miss with a weapon attack, you can make another attack against the target you missed. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Orzhov Charm",cost:200,tier:2,category:"Charm",source:"GGR, p174",description:"When you activate this charm, you can cast the bestow curse or fear spell. Alternatively, when a creature you can see within 30 feet of you is reduced to 0 hit points, you can use your reaction to have it drop to 1 hit point instead. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Selesnya Charm",cost:100,tier:2,category:"Charm",source:"GGR, p174",description:"When you activate this charm, you can cast the aura of vitality or conjure animals spell. Alternatively, as an action, you can give up to three creatures of your choice within 30 feet of you resistance to bludgeoning, piercing, and slashing damage until the end of your next turn. The charm vanishes after you activate it.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Diabolical Inspiration",cost:300,tier:3,category:"Charm",source:"BGDIA p215",description:"You grow a short, vestigial tail when you receive this charm unless you have a tail already. When you make an ability check, an attack roll, or a saving throw, you can use this charm to gain advantage on the roll. Once used nine times, the charm vanishes from you, as does your vestigial tail.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Adamant",cost:300,tier:3,category:"Charm",source:"BGDIA p215",description:"This charm has 9 charges. You can use an action to expend 1 charge from the charm to gain 30 temporary hit points. For the next hour, your eyes become voids of utter darkness, and you can't be charmed or frightened. Once all its charges have been expended, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Fates",cost:200,tier:3,category:"Charm",source:"BMT p62",description:"You can tug on the threads of fate to tweak circumstance in your favor. After you make an ability check, an attack roll, or a saving throw, you can roll a d10 and add it to the total, potentially turning failure into success. Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Moon",cost:200,tier:3,category:"Charm",source:"BMT p62",description:"As an action, you make a minor wish. When you do, you create the effects of a spell of 5th level or lower. The spell takes effect as part of this action and requires no spell components. Your Intelligence, Wisdom, or Charisma is the spellcasting ability for this spell (your choice). Once you use this charm, it vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Sun",cost:100,tier:3,category:"Charm",source:"BMT p62",description:"You learn the Light cantrip if you don't already know it. You can cast Sunburst, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used, the charm vanishes from you, and you unlearn the Light cantrip gained from this charm.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Traveler's Haven",cost:400,tier:3,category:"Charm",source:"IDRotF, p283",description:"This charm has 3 charges. As an action, you can expend 1 of the charm's charges to cast the Leomund's tiny hut spell, no components required. Once all its charges have been expended, this charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of the Throne",cost:100,tier:3,category:"Charm",source:"BMT p62",description:"You can cast Mordenkainen's Magnificent Mansion, requiring no spell components and using your Intelligence, Wisdom, or Charisma as the spellcasting ability (your choice). Once used three times, the charm vanishes from you.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Strawbundle's Charm",cost:100,tier:3,category:"Charm",source:"ToA, p179",description:"While you have Strawbundle in your possession, this charm allows you to cast the etherealness spell as an action, no components required. After it is used three times, the charm vanishes.\n\nThe doll is a Tiny construct. Destroying the doll causes the child's soul within it to become trapped in the Soulmonger.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง"},
{name:"Charm of Hellish Rebuke",cost:400,tier:4,category:"Charm",source:"BGDIA p215",description:"A fiery halo appears above your head when you receive this charm. This charm allows you to cast the hellish rebuke spell (9th-level version) as a reaction. Once used nine times, the charm vanishes from you, as does the fiery halo.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Charm อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Bestial Awakening",cost:100,tier:1,category:"Dark Bargain",source:"TCM, p118",description:"The feral world calls to your soul, howling for you to join it. You can give in to the call and transform into a beast, but the touch of silver bites you more deeply than the sharpest fang.\n\nBeast Skin. You always have the Polymorph spell prepared. You can cast it once without a spell slot or spell components but can target only yourself, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using slots you have of the appropriate level. Intelligence, Wisdom, or Charisma is your spellcasting ability for the spell when you cast it without a spell slot (choose the ability when you select this Dark Bargain).\n\nSearing Silver. Damage from Silvered Weapons ignores any Resistance or Immunity to damage you have. If you take damage from a Silvered Weapon or touch silver with your bare skin (or its equivalent), you can't regain Hit Points until you finish a Short or Long Rest.",notes:""},
{name:"Collector of Stories",cost:100,tier:1,category:"Dark Bargain",source:"TCM, p118",description:"You have an insatiable desire to gather the tales of the world. Sometimes, you inadvertently take the story of meeting another person and keep it to yourself, forever.\n\nGathered Tales. You always have the Legend Lore spell prepared. You can cast it once without a spell slot or spell components, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using slots you have of the appropriate level. Intelligence, Wisdom, or Charisma is your spellcasting ability for the spell when you cast it without a spell slot (choose the ability when you select this Dark Bargain).\n\nHoarded Stories. When you use this bargain to cast Legend Lore without a spell slot, a Friendly NPC (the GM chooses) forgets ever meeting you. You can meet them again and attempt to rebuild a relationship, but you forever cause an unsettling discomfort in them. That NPC's attitude toward you can't ever improve beyond Indifferent, and you have Disadvantage on all Charisma checks against them.",notes:""},
{name:"Shrouded Spirit",cost:200,tier:1,category:"Dark Bargain",source:"TCM, p120",description:"The pall of death drapes over you like the Shroud of Druskenvald. This shroud protects you from the depredations of the Undead, but it draws you ever nearer to their cold embrace\n.\nInured to Undeath. You have Resistance to Necrotic damage, and you have Advantage on saving throws against spells and effects created by Undead.\nUnholy Appetite. You must consume one pound of raw flesh (it needn't be fresh) per day or suffer Malnutrition.\n\nWithering Soul. Features that detect your creature type, such as a Paladin's Divine Sense or the Detect Evil and Good spell, treat you as Undead if your creature type isn't Undead already.",notes:""},
{name:"Skin of Coffin Nails",cost:200,tier:1,category:"Dark Bargain",source:"TCM, p120",description:"Your body becomes as coldly unrelenting as iron nails sealing away the dead. You can shrug off staggering punishment, but the waters of the world no longer embrace you, as if spiting your defiance.\n\nIron Grit. You gain Resistance to Bludgeoning, Piercing, or Slashing damage (your choice when you select this Dark Bargain). You can change the damage type to one of the other options when you finish a Short or Long Rest. When you suffer a Critical Hit from the chosen damage type, it becomes a normal hit instead.\n\nWatery Doom. When you are immersed in water or splashed with at least 1 gallon of water (such as from a bucket or being rained on), your skin tightens and grows rusty until you finish a Short or Long Rest. During that time, your Speed and the time you can hold your breath are halved, and your Resistance to the chosen damage type for Iron Grit becomes Vulnerability instead. At the GM's discretion, other liquids can also trigger this feature.",notes:""},
{name:"Stilled Hungers",cost:100,tier:1,category:"Dark Bargain",source:"TCM, p121",description:"Food, drink, and maladies of the flesh have lost their hold over you, but these are the very things that keep a soul vital while in the land of the living. Your mind grows ravenous absent those urges—your thoughts crack with gnawing fears, and your dreams wither into crooked nightmares.\n\nSated Cravings. Forgoing food and drink doesn't give you Exhaustion levels. You have Resistance to Poison damage, and you have Advantage on saving throws to avoid or end the Poisoned condition.\n\nTenuous Psyche. You have Vulnerability to Psychic damage and Disadvantage on saving throws to avoid or end the Frightened condition. A Calm Emotions spell cast on you suppresses this feature for its duration.",notes:""},
{name:"Wing of Whispers",cost:100,tier:2,category:"Dark Bargain",source:"TCM, p121",description:"You have been gifted with secrets that you can call upon in the form of ravens and crows to bear you aloft, but at the risk of revealing your own secrets in turn.\n\nMurderous Flight. As a Bonus Action, you can magically gain a Fly Speed equal to your Speed (and you can hover) for 10 minutes. During this time, a mass of shadows takes the shape of a murder of crows and ravens (but they aren't truly creatures). The birds appear in a 20-foot Emanation originating from you and take flight and whirl around you when you fly. Once you use this feature, you can't do so again until you finish a Short or Long Rest, unless you gain 1 Exhaustion level to use it again early.\n\nWhispered Secrets. The birds that appear when you activate Murderous Flight remain and continue to follow you until you finish a Short or Long Rest. While the birds are present, you have Disadvantage on Dexterity (Stealth) checks, and the birds whisper your secrets into the minds of other creatures, granting them Advantage on Wisdom (Insight or Perception) checks made against you.",notes:""},
{name:"Call of the Lonely",cost:100,tier:3,category:"Dark Bargain",source:"TCM, p118",description:"In the depths of your solitude, and when your hope withered on the branch, you were granted a companion you can call on. You never have to be alone again. This companion is Friendly toward you but is deeply unsettling to your allies.\n\nNever Alone. When no other creature can see you, you can use a Bonus Action to call your companion, which appears in an unoccupied space within 10 feet of you. It takes the form of a person or a vague silhouette, and it uses the Doppelganger stat block. It is Friendly toward you and acts as your ally, and it takes its turn on your Initiative in combat. It disappears after 1 hour, when it dies, when you die, or when you use an action to politely dismiss it. When it disappears, it drops anything it was wearing or carrying.\nOnce you use this Bonus Action, you can't use it again until you finish a Long Rest.\n\nUnsettling Presence. While your companion is summoned, both it and you exude a frightful air that unnerves your allies. While the companion is summoned, a creature that isn't Hostile toward you that starts its turn able to see you or the companion must succeed on a DC 15 Wisdom saving throw or have the Frightened condition until the start of its next turn.",notes:""},
{name:"Crooked Fortune",cost:200,tier:3,category:"Dark Bargain",source:"TCM, p119",description:"The crooked fate that governs Druskenvald has taken a liking to you. You can avoid calamity, but you must pay back your good fortune eventually.\n\nCheat Fate. When you fail a saving throw, you can choose to succeed instead. When you do so, if you would take half damage on a successful save, you take no damage instead. Once you use Cheat Fate, you can't use it again until you pay the price (see below).\n\nDelayed Price. After you use Cheat Fate, your next three saving throws have Disadvantage and can't have Advantage, and you gain 1 Exhaustion level when you succeed on one of the saves. Once you succeed or fail on the third saving throw, you regain the use of Cheat Fate. The powers that govern the warp and weft of fate don't take kindly to cheating outside their terms—at the GM's discretion, saving throws made intentionally or without true consequences simply to pay this price painlessly don't count.",notes:""},
{name:"Cult of Personality",cost:100,tier:3,category:"Dark Bargain",source:"TCM, p119",description:"You are a force of charm and allure with which to be reckoned. While others fall over themselves to stumble into your good graces, you might find that you end up needing them more than they need you.\n\nHoneyed Words. As an Action, you can speak sweet words to a creature within 60 feet of you. The creature has the Charmed condition for 24 hours, until you use this feature again, or until you or your allies deal any damage to the target or force it to make a saving throw. The Charmed target is your ally and follows your commands as long as they don't require the target to harm itself. If the target carries out a command it finds odious, it makes a DC 15 Wisdom saving throw, ending the condition on itself on a success. Once the condition ends, the target is immune to this feature for 24 hours.\n\nIf the target has Immunity to the Charmed condition, it instead has Disadvantage on ability checks, attack rolls, and saving throws until the start of your next turn, and you gain a number of Temporary Hit Points equal to your level. Once you use this feature, you can't use it again until you finish a Short or Long Rest.\n\nSolitary Weakness. If you start your turn with no allies that you can see or hear within 20 feet of you, you lose any Temporary Hit Points you have from any source, and you have Disadvantage on ability checks, attack rolls, and saving throws until the start of your next turn.",notes:""},
{name:"Might of the Old",cost:200,tier:3,category:"Dark Bargain",source:"TCM, p119",description:"Ancient and primeval power dwells within the oldest forests of Druskenvald. These powers pour their strength into you but can overwhelm you with their unchanging nature.\n\nAncient Might. Your Strength score increases by 2, to a maximum of 22, and your Dexterity score decreases by 2.\n\nPrimeval Strength. As a Bonus Action, you can call upon the might of the ancients to raise your Strength score to 25 for 1 minute, during which time you deal double damage to objects. Once you use this Bonus Action, you can't use it again until you finish a Long Rest.\n\nPyre's Price. When you activate Primeval Strength, your skin takes on a bark-like texture, during which time you have Vulnerability to Fire damage. Your skin returns to normal when you finish a Long Rest.",notes:""},
{name:"Unquenchable Fury",cost:400,tier:3,category:"Dark Bargain",source:"TCM, p121",description:"Anger is a powerful tool. This bargain stokes it into a formidable inferno, but it threatens to consume everything in its path.\n\nFurious Onslaught. As a Bonus Action, or when you take the Attack action on your turn, you can choose to enter a fury. While in this fury, you can make one additional melee attack when you take the Attack action on your turn, and you reduce all damage you take by an amount equal to your Proficiency Bonus. The fury ends if you have the Incapacitated condition, if you die, or if you end your turn and there are no creatures within 60 feet of you that you can see or hear. Once you use this feature, you can't use it again until you finish a Long Rest. You also regain the use of this feature when you kill a Humanoid.\n\nRed Haze. While you are in a fury, you must make a DC 15 Wisdom saving throw at the start of each of your turns. On a successful save, you can choose to end your fury or continue it. On a failed save, you no longer make the saving throw at the start of your turns, and you regard the creature nearest to you that you can see or hear as your enemy (if there are multiple, choose one at random). On each of your turns, you must move as close to the creature as possible and take the Attack action, targeting that creature with melee attacks. If you're unable to get close enough to the creature to attack it, your turn ends after you've used up all your available movement. If the creature dies or can no longer be seen or heard by you, the next nearest creature that you can see or hear becomes your new target.",notes:""},
{name:"Hand of Death",cost:300,tier:4,category:"Dark Bargain",source:"TCM, p119",description:"Death has no claim on you. In exchange for staying its cold hand without that hand closing, you become a maw through which death feeds on the world around you.\n\nAdamant Endurance. You have Advantage on Constitution saving throws.\n\nCling to Life. When you have 0 Hit Points at the start of your turn, or when you die, you can instead choose to regain a number of Hit Points equal to half your maximum. Once you use this feature, you can't use it again. After using it, whenever you regain Hit Points through any means, you gain only half that amount. Once a Humanoid (other than you) dies within 30 feet of you, you regain the use of this feature, and you can regain Hit Points as normal.\n\nDeath Knell. Other creatures within 10 feet of you have Disadvantage on Death Saving Throws, and you can't restore Hit Points to a creature with 0 Hit Points by any means.",notes:""},
{name:"Self-Serving Sacrifice",cost:100,tier:4,category:"Dark Bargain",source:"TCM, p120",description:"You can snatch others from the jaws of death, but your own grip lingers too tightly. The feeling of saving others from suffering fills you with resolve, even as it drains the vigor from those you rescue.\n\nCritical Savior. When a creature within 120 feet of you is subjected to a Critical Hit or is reduced to 0 Hit Points, you can use your Reaction to magically switch places with the target. Each of you teleports to the other's space. Roll a number of d6s equal to half your level. You take Force damage equal to the total rolled, you gain Heroic Inspiration, and your Exhaustion level, if any, is reduced by 1. The target regains Hit Points equal to the total rolled and gains 1 Exhaustion level. You can't use this feature again until you finish a Short or Long Rest.\n\nDraining Presence. When you finish a Short or Long Rest, each creature within 100 feet of you loses one Hit Points Die (before spending Hit Dice in the case of finishing a Short Rest).\nFinal Sacrifice. You can cast True Resurrection using this bargain requiring no spell slot or spell components. Intelligence, Wisdom, or Charisma is your spellcasting ability for the spell when you cast it without a spell slot (choose the ability when you select this Dark Bargain).\n\nWhen you cast the spell this way, you die, and nothing can prevent it. Your soul is bound to torment the creature you returned to life, and you can't be raised from the dead by any means. When the creature takes a Long Rest, it must roll a d20 halfway through the rest's duration. On a 1, your soul takes the form of a Wraith within 100 feet of the creature and tries to kill it. The wraith vanishes after 8 hours, or when it dies. Once the wraith appears, it can't appear again for 30 days.",notes:""},
{name:"Dark Gift of Drizlash, the Nine-Eyed Spider",cost:100,tier:2,category:"Dark Gift",source:"CoS, p192",description:"Drizlash's gift is the power to walk on walls and ceilings. This dark gift allows its beneficiary to climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.\n\nThe beneficiary of this dark gift grows an extra eye somewhere on its body. The eye is blind and ever open.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Fekre, Queen of Poxes",cost:100,tier:2,category:"Dark Gift",source:"CoS, p191",description:"Fekre's gift is the power of spreading disease. This dark gift allows its beneficiary to cast the contagion spell as an action. After it has been used three times, the dark gift vanishes.\n\nThe beneficiary of this dark gift reeks of filth.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Dark Gift of Khirad, the Star of Secrets",cost:100,tier:2,category:"Dark Gift",source:"CoS, p193",description:"Khirad's gift is the power of divination. This gift allows its beneficiary to cast the scrying spell as an action. After it has been used three times, the dark gift vanishes.\n\nThe beneficiary's voice becomes a low whisper, and its smile becomes cruel and evil.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Dark Gift of Shami-Amourae, the Lady of Delights",cost:100,tier:2,category:"Dark Gift",source:"CoS, p192",description:"Shami-Amourae's gift is the power of persuasion. This dark gift allows its beneficiary to cast the suggestion spell as an action, and saving throws against the spell have disadvantage. After it has been used three times, the dark gift vanishes.\n\nThe beneficiary of this dark gift gains an extra finger on each hand, as well as the following flaw: \"I can't get enough pleasure. I desire others to create beauty for me at all times.\"",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Dark Gift of Sykane, the Soul Hungerer",cost:100,tier:2,category:"Dark Gift",source:"CoS, p192",description:"Sykane's gift is the power to raise the recently deceased. This dark gift allows its beneficiary to cast the raise dead spell as an action. After it has been used three times, the dark gift vanishes.\n\nAs soon as this dark gift is received, the beneficiary's eyes glow a sickly yellow until the dark gift vanishes. The beneficiary also gains the following flaw: \"If I help someone, I expect payment in return.\"",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Zrin-Hala, the Howling Storm",cost:100,tier:2,category:"Dark Gift",source:"CoS, p192",description:"Zrin-Hala's gift is the power to create lightning. This dark gift allows its beneficiary to cast the lightning bolt spell as an action. After it has been used three times, the dark gift vanishes.\n\nAs soon as this dark gift is received, one side of the beneficiary's face sags and loses all feeling.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Dark Gift of Delban, the Star of Ice and Hate",cost:200,tier:3,category:"Dark Gift",source:"CoS, p193",description:"Delban's gift is the power to unleash deadly cold. This dark gift allows its beneficiary to cast the cone of cold spell as an action. After it has been used seven times, the dark gift vanishes. Until it vanishes, the beneficiary also gains the benefits of a ring of warmth.\n\nThe beneficiary of this dark gift gains the following flaw: \"Fire terrifies me.\"",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง\n(DC = spell save DC ของตัวละครหรือ 8+Prof. Bonus+CON ถ้าไม่ได้เป็น Spellcaster)"},
{name:"Dark Gift of Norganas, the Finger of Oblivion",cost:300,tier:3,category:"Dark Gift",source:"CoS, 193",description:"Norganas's gift is the power to turn life into undeath. This dark gift allows its beneficiary to cast the finger of death spell as an action. After it has been used three times, the dark gift vanishes. When it vanishes, the beneficiary must succeed on a DC 15 Constitution saving throw or drop to 0 hit points.\n\nThis dark gift turns the beneficiary's blood pitch black and viscid, like tar.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Tarakamedes, the Grave Wyrm",cost:500,tier:3,category:"Dark Gift",source:"CoS, p192",description:"Tarakamedes's gift is the power of flight. The beneficiary of this dark gift grows skeletal wings and gains a flying speed of 50 feet.\n\nThe beneficiary of this dark gift must eat bones or grave dirt to survive. At dawn, if the creature has not eaten at least 1 pound of bones or grave dirt in the past 24 hours, it dies.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Vaund the Evasive",cost:300,tier:3,category:"Dark Gift",source:"CoS, p193",description:"Vaund's gift is the power of evasion. This dark gift grants its beneficiary the benefits of an amulet of proof against detection and location and a ring of evasion. These benefits last for 10 days, after which the dark gift vanishes.\n\nThe beneficiary of this dark gift becomes twitchy and nervous, and also gains the following flaw: \"I can't give a straight answer to any question put to me.\"",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Yog the Invincible",cost:300,tier:3,category:"Dark Gift",source:"CoS, p193",description:"Yog's gift is one of physical resilience. This dark gift increases the beneficiary's hit point maximum by 30. This benefit lasts for 10 days, after which the dark gift vanishes.\n\nOily black fur covers the beneficiary's face and body.",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Dark Gift of Yrrga, the Eye of Shadows",cost:300,tier:3,category:"Dark Gift",source:"CoS, p193",description:"Yrrga's gift is the power of true seeing. This dark gift grants its beneficiary the benefits of truesight out to a range of 60 feet. These benefits last for 30 days, after which the dark gift vanishes.\n\nThe eyes of the beneficiary become starry voids until the dark gift vanishes. The beneficiary of this dark gift also gains the following flaw: \"I believe that all life is pointless and look forward to death when it finally comes.\"",notes:"เมื่อกลับเข้า The Spire จะได้รับ Dark Gift อีกครั้ง"},
{name:"Draconic Senses",cost:100,tier:1,category:"Draconic Gift",source:"FTD, p28",description:"You gain keen senses like a dragon's.\n\nBlindsight. You have blindsight to a range of 10 feet. Within that range, you can effectively see anything that isn't behind total cover, even if you're blinded or in darkness. Moreover, you can see invisible creatures within that range, unless the creatures successfully hide from you.\nKeen Senses. You have advantage on Wisdom (Perception) checks.",notes:""},
{name:"Frightful Presence",cost:300,tier:1,category:"Draconic Gift",source:"FTD, p28",description:"Echoes of a dragon's might linger around you, and you can call on them to inspire fear in those who stand against you.\n\nAs a bonus action, you can manifest your frightful presence. Each creature of your choice that is within 120 feet of you and aware of you must make a Wisdom saving throw against a DC equal to 8 + your proficiency bonus + your Charisma modifier. A creature that fails becomes frightened of you for 1 minute. The creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.\n\nOnce you use this ability a number of times equal to your proficiency bonus, you can't use it again until you finish a long rest.",notes:""},
{name:"Scaled Toughness",cost:600,tier:1,category:"Draconic Gift",source:"FTD, p28",description:"Your skin toughens, making you resistant to certain types of physical harm. You gain resistance to piercing and slashing damage",notes:""},
{name:"Tongue of the Dragon",cost:100,tier:1,category:"Draconic Gift",source:"FTD, p28",description:"You gain some of the majestic presence of a dragon.\n\nDragon's Speech. You can speak, read, and write Draconic.\nDragon's Voice. As a bonus action, you can make your voice audible up to 300 feet away for 1 minute.\nDragon's Wiles. You have advantage on Charisma (Persuasion) checks.",notes:""},
{name:"Echo of Dragonsight",cost:100,tier:2,category:"Draconic Gift",source:"FTD, p28",description:"You have begun to extend your awareness beyond the single world of the Material Plane that is your home.\n\nYou can cast contact other plane as a ritual. The entity you contact is a dragon on another world in the Material Plane, so its knowledge of your world might be limited. Also, this dragon is an echo of the dragon who is the source of the gift, which might affect its attitude and behavior toward you.",notes:""},
{name:"Psionic Reach",cost:300,tier:4,category:"Draconic Gift",source:"FTD, p28",description:"The psionic energy of a gem dragon empowers your mind. You gain resistance to psychic damage.\n\nIn addition, you learn the telekinesis spell. You can cast this spell without expending a spell slot. Once you cast this spell in this way, you can't do so again until you finish a long rest. You can also cast this spell using spell slots you have of the appropriate level. The spellcasting ability is Intelligence, Wisdom, or Charisma when you cast the spell with this gift (choose when you gain the gift).",notes:""},
{name:"Cult of Geryon",cost:100,tier:1,category:"Cult",source:"MPMM p136",description:"Crushing Blow (1/Short Rest). As a bonus action, the creature gains a bonus to the damage roll of its next melee weapon attack roll that hits within the next minute. The bonus equals its Strength modifier (minimum of +1).\nIndomitable Strength (Recharge 5–6). As a reaction when this creature takes damage, it can roll a d10 and subtract the number rolled from the damage.",notes:""},
{name:"Cult of Atropus, the World Born Dead",cost:100,tier:1,category:"Cult",source:"MTF p21",description:"Gaze of Corruption (Recharge 6). As an action, you target one creature you can see within 30 feet. The target must succeed on a Constitution saving throw against your spell save DC or take 16 (3d10) necrotic damage and be poisoned for 1 minute. The poisoned target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.",notes:""},
{name:"Cult of Baphomet",cost:100,tier:1,category:"Cult",source:"MPMM p58",description:"Labyrinthine Recall. This creature can perfectly recall any path it has traveled.\nUnerring Tracker. As a bonus action, this creature magically creates a psychic link with one creature it can see. For the next hour, as a bonus action this creature learns the current distance and direction to the target if it is on the same plane of existence. The link ends if this creature is incapacitated or if it uses this ability on a different target.",notes:""},
{name:"Cult of Mammon",cost:100,tier:1,category:"Cult",source:"MTF p21",description:"Grasping Hands (1/Short Rest). As a bonus action, this creature makes a Dexterity (Sleight of Hand) check contested by the Wisdom (Insight) check of a creature it can see within 15 feet of it. If this creature succeeds, one hand-held item of its choice that it can see on the target magically teleports to its open hand. The item can't be one that the target is holding, and it must weigh no more than 10 pounds.\n\nPromise of Wealth (1/Short Rest). As a bonus action, this creature chooses one creature it can see. Up to five allies of its choice become convinced that the target carries great wealth. Until the end of this creature's next turn, those allies gain advantage on all attack rolls against the target.",notes:""},
{name:"Cult of Yeenoghu",cost:100,tier:1,category:"Cult",source:"MPMM p270",description:"Gnashing Jaws. Melee Weapon Attack: bonus to hit equal to this creature's proficiency bonus plus its Strength modifier, reach 5 ft., one target. Hit: 1d4 + this creature's Strength modifier piercing damage.\nRampage. When this creature reduces a creature to 0 hit points with a melee attack on its turn, it can take a bonus action to move up to half its speed and make one Gnashing Jaws attack.",notes:""},
{name:"Cult of Fierna",cost:200,tier:2,category:"Cult",source:"MTF p21",description:"Loyalty beyond Death (1/Short Rest). As a reaction when an ally this creature can see is reduced to 0 hit points, that ally is instead reduced to 1 hit point and gains temporary hit points equal to this creature's Charisma score + half its number of Hit Dice.",notes:""},
{name:"Cult of Graz'zt",cost:200,tier:2,category:"Cult",source:"MPMM p148",description:"Joy from Pain. Whenever this creature suffers a critical hit, it can make one melee weapon attack as a reaction.\nMaster of Pleasures. As a reaction when this creature takes damage, it can magically grant 5 temporary hit points to itself and up to three allies within 30 feet of it.",notes:""},
{name:"Cult of Haask, the Voice of Hargut",cost:100,tier:2,category:"Cult",source:"MTF p237",description:"Haask's Presence (1/Long Rest). You transform into a Tiny, slug-like being and teleport onto the shoulder of a Humanoid that you can see within 30 feet. The targeted Humanoid must succeed on a Charisma saving throw vs your spell save DC or be charmed by you. While the target is charmed, you have control of it on the target's next turn. At the end of that turn, you teleport to an unoccupied space you can see within 30 feet and return to your normal form. You can't be targeted directly by any attack or other effect while you're in the slug-like form, but you are subject to areas of effect as normal.",notes:""},
{name:"Cult of Tharizdun, the Chained God",cost:100,tier:2,category:"Cult",source:"MTF p237",description:"Tharizdun's Spark (Recharge 6). As a bonus action, you touch a simple or martial weapon or a natural weapon, if you have one. The next creature hit by the touched weapon must succeed on a DC15 Wisdom saving throw or have disadvantage on all ability checks. The affected creature can repeat the saving throw at the end of each minute, ending the effect on itself on a success.",notes:""},
{name:"Cult of Zuggtmoy",cost:200,tier:2,category:"Cult",source:"MPMM p281",description:"Spore Kissed. This creature is immune to the charmed and frightened conditions. In addition, if it is reduced to 0 hit points, each creature within 10 feet of it takes poison damage equal to its number of Hit Dice.",notes:""},
{name:"Cult of Fraz-Urb'luu",cost:200,tier:3,category:"Cult",source:"MPMM p129",description:"Liar's Eye. This creature has advantage on Wisdom (Insight or Perception) checks.\nAs a bonus action, the creature detects the location of all illusions and hidden creatures within 15 feet of it.",notes:""},
{name:"Cult of Borem, of the Lake of Boiling Mud",cost:100,tier:3,category:"Cult",source:"MTF p237",description:"Borem's Embrace (1/Day). As an action, you touch one creature within 5 feet. The target must succeed on a Dexterity saving throw vs your spell save DC or be coated in sticky, steaming mud. While it is coated in this way, the target's speed is halved, it can't use reactions, and it takes 10 (3d6) fire damage at the start of each of its turns. The effect lasts for 1 minute, until you are incapacitated or dead, or until the target is immersed in water.",notes:""},
{name:"Cult of Demogorgon",cost:600,tier:3,category:"Cult",source:"MPMM p90",description:"Two Minds of Chaos. This creature has advantage on all Intelligence, Wisdom, and Charisma saving throws.",notes:""},
{name:"Cult of Juiblex",cost:200,tier:3,category:"Cult",source:"MPMM p160",description:"Liquid Movement. As an action, this creature can move up to 20 feet through spaces no more than an inch in diameter. It must end this movement in a space that can accommodate its full size. Otherwise, it takes 5 force damage and returns to the space where it began this movement.\nSlimy Organs. This creature has resistance to bludgeoning, piercing, and slashing damage from nonmagical attacks.\nWhenever this creature suffers a critical hit or is reduced to 0 hit points, it sprays acid; each creature within 5 feet of it takes acid damage equal to its number of Hit Dice.",notes:""},
{name:"Cult of Orcus",cost:400,tier:3,category:"Cult",source:"MPMM p204",description:"Undying Soul (1/Short Rest). If this creature is reduced to 0 hit points, it immediately makes a DC 10 Constitution saving throw. If it succeeds, it is instead reduced to 1 hit point.\n\nAura of Death. This creature emanates a deathly aura that extends 30 feet in every direction from its space while it isn't incapacitated. The aura is blocked by total cover. While in the aura, the creature and any friendly Undead are immune to the frightened condition and have resistance to radiant damage. Enemies have disadvantage on death saving throws while in the aura.",notes:""},
{name:"Cult of Tyranthraxus, the Flamed One",cost:200,tier:3,category:"Cult",source:"MTF p237",description:"Radiant Flames (1/Day). Multihued flame surround you for 1 minute, until you are incapacitated or die, or until you extinguish the flame (no action required). While inflamed, you have telepathy with a range of 30 feet, and you can teleport as a bonus action up to 30 feet to an unoccupied space you can see. In addition, every creature that starts its turn within 5 feet of you must make a Dexterity saving throw vs your spell save DC, taking 16 (3d10) radiant damage on a failed save, or half as much damage on a successful one.",notes:""},
{name:"Cult of Glasya",cost:500,tier:4,category:"Cult",source:"MTF p21",description:"Step into Shadows (1/Short Rest). As an action, this creature, along with anything it is wearing and carrying, magically becomes invisible until the end of its next turn.\nInfernal Ring Leader. As a reaction when this creature is hit by an attack, it can choose one ally it can see within 5 feet of it and cause that ally to be hit by that attack instead.",notes:""},
{name:"Cult of Mephistopheles",cost:600,tier:4,category:"Cult",source:"MTF p21",description:"Spell Shield. This creature gains advantage on saving throws against spells. If it succeeds on such a saving throw, it gains temporary hit points equal to the spell's level.\nSpell Leech. As a bonus action, this creature chooses one willing creature it can see within 30 feet of it. The target loses its lowest-level spell slot, and this creature gains it.",notes:""},
{name:"Cult of Baalzebul",cost:500,tier:4,category:"Cult",source:"MTF p21",description:"Path of Baalzebul. As a bonus action on its turn, this creature can choose one ally it can see within 30 feet of it. Until the start of this creature's next turn, it gains advantage on all ability checks and attack rolls, while the chosen ally suffers disadvantage on all ability checks, attack rolls, and saving throws.",notes:""},
{name:"Cult of Zariel",cost:500,tier:4,category:"Cult",source:"MPMM p280",description:"Ferocious Surge (1/Short Rest). When this creature hits with an attack roll that isn't a critical hit, it can turn the hit into a critical hit.\nInfernal Tactics. Immediately after rolling initiative, this creature can choose and up to three allies it can see if it isn't incapacitated. It can swap the initiative results of the chosen creatures among them.",notes:""},
{name:"Cult of Dispater",cost:600,tier:5,category:"Cult",source:"MTF p21",description:"Infernal Insight (1/Short Rest). As a bonus action, this creature gains advantage on all ability checks and attack rolls it makes until the end of the current turn.\nVexing Escape (1/Long Rest). As a reaction when this creature takes damage, it reduces that damage to 0 and teleports up to 60 feet to an unoccupied space it can see.",notes:""},
{name:"Cult of Asmodeus",cost:800,tier:5,category:"Cult",source:"MTF p21",description:"Demands of Nessus. At the start of each of your turns, you can choose one ally you can see within 30 feet. The chosen ally loses 10 hit points, and you regain the same number of hit points. If you are incapacitated, you make no choice; instead, the closest ally within 30 feet is the chosen ally. \n\nNote: this will be perceptible.\n\nNote 2: This counts as PvP if you are choosing another PC, and will require OOC consent.",notes:""},
{name:"Demonic Boon of Goristro",cost:100,tier:1,category:"Demonic Boon",source:"MTF p32",description:"Labyrinthine Recall. This creature can perfectly recall any path it has traveled.",notes:""},
{name:"Demonic Boon of Nalfeshnee",cost:100,tier:1,category:"Demonic Boon",source:"MTF p32",description:"Guarded Mind. This creature is immune to the frightened condition.",notes:""},
{name:"Demonic Boon of Balor",cost:100,tier:2,category:"Demonic Boon",source:"MTF p32",description:"Fiery Soul. This creature has resistance to fire damage. When it dies, it explodes; each creature within 10 feet of it takes fire damage equal to its number of Hit Dice.",notes:""},
{name:"Demonic Boon of Marilith",cost:500,tier:4,category:"Demonic Boon",source:"MTF p32",description:"Serpentine Reaction. This creature can take an extra reaction each round, but this reaction can be used only to make an opportunity attack.",notes:""},
];
